import React, { useState } from 'react';

const App = () => {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white rounded p-4 w-96">
        <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Post Title" className="p-2 w-full rounded" />
        <textarea value={content} onChange={(e) => setContent(e.target.value)} rows="5" className="p-2 w-full rounded mt-2" />
        <button className="bg-[#C06C88] hover:bg-[#411C56] text-white font-bold py-2 px-4 rounded">Save</button>
      </div>
    </div>
  );
};

export default App;
